mapper.update:
/* com.educare.edu.comn.mapper.LectureTimeStdntMapper.updateByPk */
	update t_lecture_time_stdnt

		 mov_time = #{movTime}, 
		 mov_all_time = #{movAllTime}, 
		 mov_re = #{movRe}, 

	where edu_seq=#{eduSeq} and time_seq=#{timeSeq} and user_id=#{userId}

/* com.educare.edu.comn.mapper.LectureTimeStdntMapper.updateByEduSeqTimeSeq */
	update t_lecture_time_stdnt

		 mov_time = #{movTime}, 
		 mov_all_time = #{movAllTime}, 
		 mov_re = #{movRe}, 

	where edu_seq=#{eduSeq} and time_seq=#{timeSeq}

mapper.select:
/* com.educare.edu.comn.mapper.LectureTimeStdntMapper.selectByEduSeqTimeSeq */
select * from t_lecture_time_stdnt
where edu_seq=#{eduSeq} and time_seq=#{timeSeq}

	/* com.educare.edu.comn.mapper.LectureTimeStdntMapper.selectByEduSeqUserId */

	select a.edu_seq,a.time_seq ,b.user_id,b.mov_time,b.mov_all_time
 from t_lecture_time a 
 left join (select * from t_lecture_time_stdnt where user_id=#{userId}) b
 on a.edu_seq =b.edu_seq and a.time_seq =b.time_seq 
 where a.edu_seq=#{eduSeq}
